const navbar=document.getElementById("navbar");window.addEventListener("scroll",()=>{navbar.classList.toggle("scrolled",window.scrollY>40)},{passive:!0});const hamburger=document.getElementById("hamburger"),navLinks=document.getElementById("navLinks");hamburger.addEventListener("click",()=>{navLinks.classList.toggle("open"),hamburger.setAttribute("aria-expanded",navLinks.classList.contains("open"))}),navLinks.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{navLinks.classList.remove("open")})});const reveals=document.querySelectorAll(".plan-card, .structure-card, .modality-card, .unit-card, .about-content, .about-img, .section-header");reveals.forEach(e=>e.classList.add("reveal"));const observer=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("visible"),observer.unobserve(e.target))})},{threshold:.12});reveals.forEach(e=>observer.observe(e)),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){const t=document.querySelector(this.getAttribute("href"));if(t){e.preventDefault();const r=80,n=t.getBoundingClientRect().top+window.scrollY-r;window.scrollTo({top:n,behavior:"smooth"})}})});